//#region src/adapter/bun.ts
const bunAdapter = () => {
	if (typeof globalThis.navigator === "undefined") globalThis.navigator = { userAgent: "Bun" };
	else Object.defineProperty(globalThis.navigator, "userAgent", {
		value: "Bun",
		writable: false
	});
	return { env: process.env };
};
//#endregion
export { bunAdapter, bunAdapter as default };
